18→  const handleSubmit = (e: React.FormEvent<HTMLFormElement>) => {
19→    e.preventDefault();
20→    const formData = new FormData(e.currentTarget);
21→    const prompt = formData.get('prompt') as string;
22→    if (prompt.trim()) send(prompt.trim());
23→  };
24→
25→  return (
26→    <div className="min-h-screen bg-background p-8">
27→      <div className="mx-auto max-w-3xl">
28→        <div className="mb-6 flex items-center justify-between">
29→          <h1 className="text-2xl font-bold">Generative UI — Quick Start Test</h1>
30→          {spec && (
31→            <button
32→              type="button"
33→              onClick={clear}
34→              className="rounded border px-3 py-1 text-sm text-muted-foreground hover:bg-muted"
35→            >
36→              清除
37→            </button>
38→          )}
39→        </div>
40→
41→        <StateProvider initialState={{}}>
42→          <VisibilityProvider>
43→            <ActionProvider handlers={{}}>
44→              <ValidationProvider customFunctions={{}}>
45→                {/* Input form */}
46→                <form onSubmit={handleSubmit} className="mb-8 flex gap-2">
47→                  <input
48→                    name="prompt"
49→                    placeholder="描述你想要的 UI，例如：生成一个杭州旅行推荐卡片"
50→                    className="flex-1 rounded border bg-background px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-primary"
51→                    disabled={isStreaming}
52→                  />
53→                  <button
54→                    type="submit"
55→                    disabled={isStreaming}
56→                    className="rounded bg-primary px-4 py-2 text-sm font-medium text-primary-foreground disabled:opacity-50"
57→                  >
58→                    {isStreaming ? '生成中…' : '生成'}
59→                  </button>
60→                </form>
61→
62→                {/* Error */}
63→                {error && (
64→                  <div className="mb-4 rounded border border-destructive/30 bg-destructive/10 px-4 py-3 text-sm text-destructive">
65→                    {error.message}
