 1→import { Body, Controller, Post, Res } from '@nestjs/common';
 2→import { Response } from 'express';
 3→import type { BaseChatModel } from '@langchain/core/language_models/chat_models';
 4→import { SystemMessage, HumanMessage } from '@langchain/core/messages';
 5→import { catalog } from '../../agents/generative-ui/catalog';
 6→import { getModel, EModelName } from '../../config/model';
 7→
 8→@Controller('/api/generative-ui')
 9→export class GenerativeUIController {
10→  @Post('generate')
11→  async generate(
12→    @Body() body: { prompt?: string; context?: unknown; currentSpec?: unknown },
13→    @Res() res: Response,
14→  ): Promise<void> {
15→    const prompt = body.prompt?.trim();
16→    if (!prompt) {
17→      res.status(400).json({ error: 'prompt is required' });
18→      return;
19→    }
20→
21→    res.setHeader('Content-Type', 'text/plain; charset=utf-8');
22→    res.setHeader('Cache-Control', 'no-cache');
23→    res.setHeader('X-Accel-Buffering', 'no');
24→
25→    try {
26→      const model = getModel(EModelName.DeepSeekChat) as BaseChatModel;
27→      const stream = await model.stream([
28→        new SystemMessage(catalog.prompt()),
29→        new HumanMessage(prompt),
30→      ]);
31→
32→      for await (const chunk of stream) {
33→        const text = typeof chunk.content === 'string' ? chunk.content : '';
34→        if (text) res.write(text);
35→      }
36→    } catch (err) {
37→      const message = err instanceof Error ? err.message : String(err);
38→      if (!res.headersSent) {
39→        res.status(500).json({ error: message });
40→        return;
41→      }
42→    }
43→
44→    res.end();
45→  }
46→}
