 1→export interface IGenerativeUIPayload {
 2→  kind: 'generative-ui';
 3→  title: string;
 4→  spec: Record<string, unknown>;
 5→  interactive?: boolean;
 6→}
 7→
 8→export interface IResumePayload {
 9→  interruptId?: string;
10→  answer: string | Record<string, unknown>;
11→}
12→
13→export function formatGenerativeUIAnswer(answer: unknown): string {
14→  if (typeof answer === 'string') return answer;
15→
16→  if (!answer || typeof answer !== 'object' || Array.isArray(answer)) {
17→    return '用户未提供信息';
18→  }
19→
20→  const entries = Object.entries(answer as Record<string, unknown>)
21→    .map(([key, value]) => `- ${key}: ${formatValue(value)}`)
22→    .join('\n');
23→
24→  return entries ? `用户回复：\n\n${entries}` : '用户未提供信息';
25→}
26→
27→function formatValue(value: unknown): string {
28→  if (Array.isArray(value)) {
29→    return value.map(it => String(it)).join(', ');
30→  }
31→  if (value == null || value === '') {
32→    return '未填写';
33→  }
34→  return String(value);
35→}
