 1→import { useRef, useCallback, useMemo } from 'react';
 2→import {
 3→  Renderer,
 4→  StateProvider,
 5→  ActionProvider,
 6→  VisibilityProvider,
 7→  ValidationProvider,
 8→  createStateStore,
 9→} from '@json-render/react';
10→import { registry } from '@/lib/generative-ui/registry';
11→
12→interface SpecShape {
13→  root: string;
14→  elements: Record<string, unknown>;
15→  state?: Record<string, unknown>;
16→  [key: string]: unknown;
17→}
18→
19→interface GenerativeUICardProps {
20→  spec: Record<string, unknown>;
21→  initialState?: Record<string, unknown>;
22→  interactive?: boolean;
23→  disabled?: boolean;
24→  onSubmit?: (formData: Record<string, unknown> | null) => void;
25→}
26→
27→function toSpec(raw: Record<string, unknown>): SpecShape {
28→  return {
29→    root: (raw.root as string) ?? 'main',
30→    elements: (raw.elements as Record<string, unknown>) ?? {},
31→    state: (raw.state as Record<string, unknown>) ?? {},
32→    ...raw,
33→  };
34→}
35→
36→const NOOP_HANDLERS = {};
37→
38→export function GenerativeUICard({
39→  spec: rawSpec,
40→  initialState,
41→  interactive = false,
42→  disabled,
43→  onSubmit,
44→}: GenerativeUICardProps) {
45→  const spec = toSpec(rawSpec);
46→  const storeRef = useRef(
47→    createStateStore((initialState ?? spec.state ?? {}) as Record<string, unknown>),
48→  );
49→
50→  const handlers = useCallback(
51→    () => ({
52→      submit: () => {
53→        if (disabled) return;
54→        const snapshot = storeRef.current.getSnapshot();
55→        onSubmit?.(snapshot as Record<string, unknown>);
56→      },
57→      cancel: () => {
58→        if (disabled) return;
59→        onSubmit?.(null);
60→      },
61→    }),
62→    [disabled, onSubmit],
63→  );
64→
65→  const actionHandlers = useMemo(
66→    () => (interactive && onSubmit ? handlers() : NOOP_HANDLERS),
67→    [interactive, onSubmit, handlers],
68→  );
69→
70→  return (
71→    <StateProvider store={storeRef.current}>
72→      <ValidationProvider>
73→        <VisibilityProvider>
74→          <ActionProvider handlers={actionHandlers}>
75→            <Renderer spec={spec as any} registry={registry} />
76→          </ActionProvider>
77→        </VisibilityProvider>
78→      </ValidationProvider>
79→    </StateProvider>
80→  );
81→}
