478→  function finalizeToolDetailResult(
479→    toolName: typeof TOOL_WRITE_FILE | typeof TOOL_EXECUTE,
480→    data: Record<string, unknown>,
481→    event: ChatEvent,
482→    sourceState: SourceScopedState,
483→    source: StreamSource,
484→  ): void {
485→    const messageId = sourceState.detailMessageIds[toolName];
486→    if (!messageId) return;
487→    const existing = getMessageById(messageId);
488→    if (!existing?.toolDetail) return;
489→
490→    const isError = !!data.error;
491→    const output = toolName === TOOL_EXECUTE ? formatEventContent(event) : existing.toolDetail.output;
492→    const nextDetail: ToolDetail = {
493→      ...existing.toolDetail,
494→      status: isError ? 'error' : 'completed',
495→      output,
496→      summary: `${existing.toolDetail.title} · ${isError ? '失败' : '已完成'}`,
497→    };
498→
499→    updateById(messageId, msg => ({
500→      ...msg,
501→      event: EVENT_TOOL_CALL_RESULT,
502→      content: nextDetail.summary,
503→      timestamp: resolveEventTimestamp(event),
504→      toolName,
505→      toolCallId: getToolCallId(data) || msg.toolCallId,
506→      node: event.node,
507→      outputLength: typeof data.outputLength === 'number' ? data.outputLength as number : msg.outputLength,
508→      isError,
509→      toolDetail: nextDetail,
510→      ...getSubagentFields(source),
511→      source,
512→    }));
513→
514→    sourceState.detailMessageIds[toolName] = undefined;
515→    sourceState.detailBuffers[toolName] = '';
516→  }
