import { Body, Controller, Post, Res } from '@nestjs/common';
import { Response } from 'express';
import type { BaseChatModel } from '@langchain/core/language_models/chat_models';
import { SystemMessage, HumanMessage } from '@langchain/core/messages';
import { catalog } from '../../agents/generative-ui/catalog';
import { getModel, EModelName } from '../../config/model';

@Controller('/api/generative-ui')
export class GenerativeUIController {
  @Post('generate')
  async generate(
    @Body() body: { prompt?: string; context?: unknown; currentSpec?: unknown },
    @Res() res: Response,
  ): Promise<void> {
    const prompt = body.prompt?.trim();
    if (!prompt) {
      res.status(400).json({ error: 'prompt is required' });
      return;
    }

    res.setHeader('Content-Type', 'text/plain; charset=utf-8');
    res.setHeader('Cache-Control', 'no-cache');
    res.setHeader('X-Accel-Buffering', 'no');

    try {
      const model = getModel(EModelName.DeepSeekChat) as BaseChatModel;
      const stream = await model.stream([
        new SystemMessage(catalog.prompt()),
        new HumanMessage(prompt),
      ]);

      for await (const chunk of stream) {
        const text = typeof chunk.content === 'string' ? chunk.content : '';
        if (text) res.write(text);
      }
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      if (!res.headersSent) {
        res.status(500).json({ error: message });
        return;
      }
    }

    res.end();
  }
}

