113→const generativeUIPromptMiddleware = createMiddleware({
114→  name: 'GenerativeUIPromptMiddleware',
115→  wrapModelCall: async (request, handler) => {
116→    const prompt = new SystemMessage({ content: GENERATIVE_UI_PROMPT });
117→    return handler({
118→      ...request,
119→      messages: [prompt, ...request.messages],
120→    });
121→  },
122→});
