124→/**
125→ * Stricter threshold for evicting large tool results to filesystem.
126→ * Default in deepagents SDK is 20000 tokens (80000 chars).
127→ * We use 5000 tokens (20000 chars) to aggressively evict large MCP tool results
128→ * (e.g., query_prometheus, get_dashboard_by_uid) that can return 60k-120k+ chars.
129→ */
130→const STRICT_TOOL_TOKEN_LIMIT = 5000;
131→const NUM_CHARS_PER_TOKEN = 4;
132→const STRICT_CHAR_LIMIT = STRICT_TOOL_TOKEN_LIMIT * NUM_CHARS_PER_TOKEN;
133→
134→/** Tools whose results should never be touched by eviction middleware. */
135→const TOOLS_EXCLUDED_FROM_EVICTION = ['ls', 'glob', 'grep', 'edit_file', 'write_file'];
136→
137→/**
138→ * Tools that should be truncated in-place (not evicted to file) when too large.
139→ * read_file is here because evicting to file would create an infinite loop
140→ * (read → evict → read again → still too big). Instead we truncate directly
141→ * and prompt the model to narrow its query.
142→ */
143→const TOOLS_TRUNCATED_IN_PLACE = ['read_file'];
144→
145→function sanitizeToolCallId(toolCallId: string): string {
146→  return toolCallId.replace(/\./g, '_').replace(/\//g, '_').replace(/\\/g, '_');
147→}
148→
149→function createContentPreview(content: string, headLines = 5, tailLines = 5): string {
150→  const lines = content.split('\n');
151→  if (lines.length <= headLines + tailLines) {
152→    return lines.map((line, i) => `${i + 1}\t${line.substring(0, 1000)}`).join('\n');
153→  }
154→  const head = lines.slice(0, headLines).map((line, i) => `${i + 1}\t${line.substring(0, 1000)}`).join('\n');
155→  const truncation = `\n... [${lines.length - headLines - tailLines} lines truncated] ...\n`;
156→  const tailStart = lines.length - tailLines + 1;
157→  const tail = lines.slice(-tailLines).map((line, i) => `${tailStart + i}\t${line.substring(0, 1000)}`).join('\n');
158→  return head + truncation + tail;
159→}
