161→const TOO_LARGE_MSG = `Tool result too large, the result of this tool call {tool_call_id} was saved in the filesystem at this path: {file_path}
162→You can read the result from the filesystem by using the read_file tool, but make sure to only read part of the result at a time.
163→You can do this by specifying an offset and limit in the read_file tool call.
164→For example, to read the first 100 lines, you can use the read_file tool with offset=0 and limit=100.
165→
166→Here is a preview showing the head and tail of the result (lines of the form
167→... [N lines truncated] ...
168→indicate omitted lines in the middle of the content):
169→
170→{content_sample}`;
171→
172→const READ_FILE_TRUNCATED_MSG = `File content too large ({total_chars} chars, {total_lines} lines). Only the first {limit_chars} chars are shown below.
173→
174→IMPORTANT: Do NOT keep reading this file in large chunks — that will flood your context with raw data.
175→Instead, think about what specific information you need and use one of these strategies:
176→- Use read_file with a narrow offset/limit to read only the relevant section
177→- Use grep to search for specific keys or values within the file
178→- If the file is JSON, consider whether a more targeted tool (e.g., get_dashboard_summary, get_dashboard_property) can give you what you need directly
179→
180→{truncated_content}`;
181→
182→/**
183→ * Creates a middleware that evicts large tool results to the VFS filesystem
184→ * with a stricter threshold than the default deepagents SDK.
185→ *
186→ * Custom middleware runs innermost in the chain, so our eviction happens
187→ * before the SDK's built-in filesystem middleware sees the result.
188→ */
189→function createStrictToolEvictionMiddleware(backend: SandboxBackendProtocol) {
190→  return createMiddleware({
191→    name: 'StrictToolEvictionMiddleware',
192→    wrapToolCall: async (request, handler) => {
193→      const toolName = request.toolCall?.name;
194→      if (toolName && TOOLS_EXCLUDED_FROM_EVICTION.includes(toolName)) {
195→        return handler(request);
196→      }
197→
198→      const result = await handler(request);
199→
200→      if (!ToolMessage.isInstance(result) || typeof result.content !== 'string' || result.content.length <= STRICT_CHAR_LIMIT) {
201→        return result;
202→      }
203→
204→      if (toolName && TOOLS_TRUNCATED_IN_PLACE.includes(toolName)) {
205→        const totalChars = result.content.length;
206→        const totalLines = result.content.split('\n').length;
207→        return new ToolMessage({
208→          content: READ_FILE_TRUNCATED_MSG
209→            .replace('{total_chars}', String(totalChars))
210→            .replace('{total_lines}', String(totalLines))
211→            .replace('{limit_chars}', String(STRICT_CHAR_LIMIT))
212→            .replace('{truncated_content}', result.content.slice(0, STRICT_CHAR_LIMIT)),
213→          tool_call_id: result.tool_call_id,
214→          name: result.name,
215→          id: result.id,
216→          artifact: (result as any).artifact,
217→          status: result.status,
218→          metadata: result.metadata,
219→          additional_kwargs: result.additional_kwargs,
220→          response_metadata: result.response_metadata,
221→        });
222→      }
223→
224→      const toolCallId = request.toolCall?.id || result.tool_call_id;
225→      const evictPath = `/large_tool_results/${sanitizeToolCallId(toolCallId)}`;
226→
227→      let contentToWrite = result.content;
228→      try {
229→        const parsed = JSON.parse(contentToWrite);
230→        contentToWrite = JSON.stringify(parsed, null, 2);
231→      } catch { }
232→
233→      const writeResult = await backend.write(evictPath, contentToWrite);
234→      if (writeResult.error) return result;
235→
236→      const contentSample = createContentPreview(result.content);
237→      return new ToolMessage({
238→        content: TOO_LARGE_MSG
239→          .replace('{tool_call_id}', result.tool_call_id)
240→          .replace('{file_path}', evictPath)
241→          .replace('{content_sample}', contentSample),
242→        tool_call_id: result.tool_call_id,
243→        name: result.name,
244→        id: result.id,
245→        artifact: (result as any).artifact,
246→        status: result.status,
247→        metadata: result.metadata,
248→        additional_kwargs: result.additional_kwargs,
249→        response_metadata: result.response_metadata,
250→      });
251→    },
252→  });
253→}
