255→export default async function createSimpleDeepAgent(
256→  model: BaseLanguageModel,
257→  conversationId: string,
258→  sandboxManager: ConversationSandboxManager,
259→): Promise<ReturnType<typeof createDeepAgent>> {
260→  const session = await sandboxManager.getConversationSandbox(conversationId);
261→  const client = new MultiServerMCPClient({
262→    grafana: {
263→      transport: 'sse',
264→      url: configSchema.GRAFANA_MCP_URL!,
265→    },
266→  });
267→
268→  // 过滤，只剩下
269→  const FILTER_TOOLS = ['search_dashboards', 'list_datasources', 'get_dashboard_summary', 'get_dashboard_property', 'get_dashboard_panel_queries', 'query_prometheus', 'list_prometheus_label_names', 'generate_deeplink'];
270→  const allMcpTools = (await client.getTools()).filter(tool => FILTER_TOOLS.includes(tool.name)) as DynamicStructuredTool[]
271→
272→  return createDeepAgent({
273→    model: model,
274→    tools: [...allMcpTools, renderUITool],
275→    sharedMiddleware: [
276→      contextOverflowBridgeMiddleware,
277→      vfsRelativePathMiddleware,
278→      generativeUIPromptMiddleware,
279→      createToolErrorMiddleware(),
280→      createStrictToolEvictionMiddleware(session.backend),
281→    ],
282→    backend: session.backend,
283→    checkpointer: memory,
284→    skills: [SANDBOX_SKILLS_ROOT]
285→  });
286→}
