  1→import { GenerativeUIMessage, GenerativeUIPayload, ChatEvent, Message, StreamSource, TodoItem, TodoTreeItem, ToolDetail } from '@/types';
  2→import { parse as parsePartialJson } from 'partial-json';
  3→import {
  4→  buildToolDetailFromArgs,
  5→  formatEventContent,
  6→  generateId,
  7→  getEventContent,
  8→  getToolInputData,
  9→  isDetailToolName,
 10→} from './chatUtils';
 11→import { parseTokenUsageFromAssistantEndData } from './tokenUsage';
 12→import {
 13→  EVENT_USER,
 14→  EVENT_ASSISTANT,
 15→  EVENT_THINKING,
 16→  EVENT_TOOL_INPUT,
 17→  EVENT_TOOL_CALL,
 18→  EVENT_TOOL_CALL_RESULT,
 19→  EVENT_DELIVER,
 20→  EVENT_ERROR,
 21→  EVENT_TOOL_OUTPUT,
 22→  EVENT_GENERATIVE_UI,
 23→  EVENT_SET_GENERATIVE_UI_ANSWER,
 24→  EVENT_CONTEXT_SUMMARIZED,
 25→  EVENT_TODO_UPDATE,
 26→  EVENT_AGENT_END,
 27→  EVENT_ASSISTANT_END,
 28→  FILTERED_MESSAGE_EVENTS,
 29→  TOOL_WRITE_TODOS,
 30→  TOOL_RENDER_UI,
 31→  TOOL_WRITE_FILE,
 32→  TOOL_EXECUTE,
 33→} from './const';
 34→
 35→// ─── write_todos JSON extraction ─────────────────────────────────────────────
 36→
 37→const VALID_TODO_STATUSES = new Set(['pending', 'in_progress', 'completed']);
 38→
 39→function parseTodoItems(accumulated: string): TodoItem[] {
 40→  try {
 41→    const parsed = parsePartialJson(accumulated);
 42→    return sanitizeTodoItems(parsed?.todos);
 43→  } catch {
 44→    return [];
 45→  }
 46→}
 47→
 48→function sanitizeTodoItems(todos: unknown): TodoItem[] {
 49→  if (!Array.isArray(todos)) {
 50→    return [];
 51→  }
 52→
 53→  return todos.filter(
 54→    (item): item is TodoItem =>
 55→      typeof item?.content === 'string' && VALID_TODO_STATUSES.has(item.status),
 56→  );
 57→}
 58→
 59→function toTodoTree(todos: TodoItem[]): TodoTreeItem[] {
 60→  return todos.map(todo => ({
 61→    ...todo,
 62→    children: [],
 63→  }));
 64→}
 65→
 66→const FILTERED_MESSAGE_EVENT_SET = new Set<string>(FILTERED_MESSAGE_EVENTS);
 67→
 68→function asString(value: unknown): string | undefined {
 69→  return typeof value === 'string' ? value : undefined;
 70→}
 71→
 72→function parseGenerativeUIPreview(accumulated: string): GenerativeUIMessage | undefined {
 73→  try {
 74→    const parsed = parsePartialJson(accumulated);
 75→    if (!parsed || typeof parsed !== 'object') return undefined;
 76→
 77→    const data = parsed as Record<string, unknown>;
 78→    const title = asString(data.title) || '';
 79→    const spec = data.spec as Record<string, unknown> | undefined;
 80→    if (!title && !spec) return undefined;
 81→
 82→    return {
 83→      title: title || 'UI',
 84→      spec: spec ?? {},
 85→      interactive: data.interactive === true,
 86→      isPreview: true,
 87→    };
 88→  } catch {
 89→    return undefined;
 90→  }
 91→}
 92→
 93→// ─── Processor ────────────────────────────────────────────────────────────────
 94→
 95→interface ProcessorState {
 96→  messages: Message[];
 97→  todoTree: TodoTreeItem[];
 98→  sourceStates: Record<string, SourceScopedState>;
 99→}
100→
101→interface SourceScopedState {
102→  currentAssistantId: string | undefined;
103→  todoMessageId: string | undefined;
104→  todoBuffer: string;
105→  generativeUIPreviewMessageId: string | undefined;
106→  generativeUIPreviewBuffer: string;
107→  detailMessageIds: Partial<Record<typeof TOOL_WRITE_FILE | typeof TOOL_EXECUTE, string>>;
108→  detailBuffers: Partial<Record<typeof TOOL_WRITE_FILE | typeof TOOL_EXECUTE, string>>;
109→}
110→
111→/**
112→ * 创建一个有状态的消息处理器。
113→ * 同一套 applyEvent 逻辑被流式处理和历史加载共享，确保两路径产出完全一致的 Message[]。
114→ *
115→ * - 流式：每次 applyEvent 后调用 setMessages([...processor.getMessages()])
116→ * - 历史：批量 applyEvent，最后调用 setMessages(processor.getMessages())
117→ */
118→export function createMessageProcessor(initialMessages: Message[] = []) {
119→  const state: ProcessorState = {
120→    messages: [...initialMessages],
121→    todoTree: [],
122→    sourceStates: {},
123→  };
124→
125→  // ── helpers ──────────────────────────────────────────────────────────────────
126→
127→  function getSourceKey(source?: StreamSource): string {
128→    return source?.key || 'main';
129→  }
130→
131→  function isSameSource(left?: StreamSource, right?: StreamSource): boolean {
132→    return (left?.kind || 'main') === (right?.kind || 'main') && getSourceKey(left) === getSourceKey(right);
133→  }
134→
135→  function resolveEventSource(event: ChatEvent): StreamSource {
136→    if (event.subagentNamespace) {
137→      return {
138→        kind: 'subagent',
139→        key: event.subagentNamespace,
140→        label: event.subagentType,
141→      };
142→    }
143→    return event.source || { kind: 'main', key: 'main', label: event.node };
144→  }
145→
146→  function getSubagentFields(source: StreamSource): Pick<Message, 'subagentType' | 'subagentNamespace'> {
147→    return source.kind === 'subagent'
148→      ? {
149→          subagentType: source.label,
150→          subagentNamespace: source.key,
151→        }
152→      : {
153→          subagentType: undefined,
154→          subagentNamespace: undefined,
155→        };
156→  }
157→
158→  function getSourceState(source: StreamSource): SourceScopedState {
159→    const key = getSourceKey(source);
160→    if (!state.sourceStates[key]) {
161→      state.sourceStates[key] = {
162→        currentAssistantId: undefined,
163→        todoMessageId: undefined,
164→        todoBuffer: '',
165→        generativeUIPreviewMessageId: undefined,
166→        generativeUIPreviewBuffer: '',
167→        detailMessageIds: {},
168→        detailBuffers: {},
169→      };
170→    }
171→    return state.sourceStates[key];
172→  }
173→
174→  for (const message of initialMessages) {
175→    const source = message.source || { kind: 'main', key: 'main', label: message.node };
176→    const sourceState = getSourceState(source);
177→    if (message.event === EVENT_TODO_UPDATE) {
178→      sourceState.todoMessageId = message.id;
179→      syncMainTodoTree(source, sanitizeTodoItems(message.todos));
180→    }
181→  }
182→
183→  function push(msg: Omit<Message, 'id'> & { id?: string }): Message {
184→    const m = { ...msg, id: msg.id || generateId() } as Message;
185→    state.messages.push(m);
186→    return m;
187→  }
188→
189→  function updateById(id: string, updater: (msg: Message) => Message): void {
190→    const idx = state.messages.findIndex(m => m.id === id);
191→    if (idx !== -1) state.messages[idx] = updater(state.messages[idx]);
192→  }
193→
194→  function resolveEventId(event: ChatEvent): string {
195→    return event.id || generateId();
196→  }
197→
198→  function resolveEventTimestamp(event: ChatEvent): number {
199→    return typeof event.timestamp === 'number' ? event.timestamp : Date.now();
200→  }
201→
202→  function getToolCallId(data: Record<string, unknown> | undefined): string | undefined {
203→    return typeof data?.id === 'string' ? data.id : undefined;
204→  }
205→
206→  function parseStructuredInput(accumulated: string): Record<string, unknown> | undefined {
207→    if (!accumulated) return undefined;
208→    try {
209→      const parsed = parsePartialJson(accumulated);
210→      return parsed && typeof parsed === 'object' && !Array.isArray(parsed)
211→        ? parsed as Record<string, unknown>
212→        : undefined;
213→    } catch {
214→      return undefined;
215→    }
216→  }
217→
218→  function getMessageById(id: string | undefined): Message | undefined {
219→    if (!id) return undefined;
220→    return state.messages.find(message => message.id === id);
221→  }
222→
223→  // ── generative-ui helpers ────────────────────────────────────────────────────
224→
225→  function finalizeGenerativeUI(payload: GenerativeUIPayload, event: ChatEvent, sourceState: SourceScopedState, source: StreamSource): void {
226→    const timestamp = resolveEventTimestamp(event);
227→    const content = payload.title || 'UI';
228→
229→    const finalizedPayload: GenerativeUIMessage = {
230→      ...payload,
231→      isPreview: false,
232→    };
233→
234→    if (sourceState.generativeUIPreviewMessageId) {
235→      updateById(sourceState.generativeUIPreviewMessageId, msg => ({
236→        ...msg,
237→        role: 'assistant',
238→        content,
239→        timestamp,
240→        event: EVENT_GENERATIVE_UI,
241→        node: event.node,
242→        generativeUI: finalizedPayload,
243→        ...getSubagentFields(source),
244→        source,
245→      }));
246→      sourceState.generativeUIPreviewMessageId = undefined;
247→      sourceState.generativeUIPreviewBuffer = '';
248→      return;
249→    }
250→
251→    push({
252→      role: 'assistant',
253→      content,
254→      timestamp,
255→      event: EVENT_GENERATIVE_UI,
256→      node: event.node,
257→      generativeUI: finalizedPayload,
258→      ...getSubagentFields(source),
259→      source,
260→    });
261→    sourceState.generativeUIPreviewMessageId = undefined;
262→    sourceState.generativeUIPreviewBuffer = '';
263→  }
264→
265→  function upsertGenerativeUIPreview(payload: GenerativeUIMessage, event: ChatEvent, sourceState: SourceScopedState, source: StreamSource): void {
266→    const timestamp = resolveEventTimestamp(event);
267→    const content = payload.title || 'UI';
268→    if (!content && !payload.spec) return;
269→
270→    if (sourceState.generativeUIPreviewMessageId) {
271→      updateById(sourceState.generativeUIPreviewMessageId, msg => ({
272→        ...msg,
273→        role: 'assistant',
274→        content: content || msg.content,
275→        timestamp,
276→        event: EVENT_GENERATIVE_UI,
277→        node: event.node,
278→        generativeUI: payload,
279→        ...getSubagentFields(source),
280→        source,
281→      }));
282→      return;
283→    }
284→
285→    sourceState.generativeUIPreviewMessageId = generateId();
286→    push({
287→      id: sourceState.generativeUIPreviewMessageId,
288→      role: 'assistant',
289→      content: content || 'UI',
290→      timestamp,
291→      event: EVENT_GENERATIVE_UI,
292→      node: event.node,
293→      generativeUI: payload,
294→      ...getSubagentFields(source),
295→      source,
296→    });
297→  }
298→
299→  // ── todo helpers ─────────────────────────────────────────────────────────────
300→
301→  function syncMainTodoTree(source: StreamSource, todos: TodoItem[]): void {
302→    if (source.kind === 'main') {
303→      state.todoTree = toTodoTree(todos);
304→    }
305→  }
306→
307→  function createTodoUpdateMessage(
308→    todos: TodoItem[],
309→    event: ChatEvent,
310→    sourceState: SourceScopedState,
311→    source: StreamSource,
312→    timestamp: number,
313→  ): void {
314→    sourceState.todoMessageId = generateId();
315→    syncMainTodoTree(source, todos);
316→    push({
317→      id: sourceState.todoMessageId,
318→      role: 'assistant',
319→      content: '',
320→      timestamp,
321→      event: EVENT_TODO_UPDATE,
322→      node: event.node,
323→      todos,
324→      ...getSubagentFields(source),
325→      source,
326→    });
327→  }
328→
329→  function upsertTodo(todos: TodoItem[], event: ChatEvent, sourceState: SourceScopedState, source: StreamSource): void {
330→    const timestamp = resolveEventTimestamp(event);
331→    if (sourceState.todoMessageId) {
332→      updateById(sourceState.todoMessageId, msg => {
333→        const oldTodos = msg.todos || [];
334→        // 流式解析时 partial-json 可能产出 content 为空字符串的不完整条目，
335→        // 只有新条目的 content 非空时才覆盖旧数据，避免已有内容被清空。
336→        const mergedTodos = oldTodos.map((todo, index) => {
337→          const newTodo = todos[index];
338→          return (newTodo?.content) ? newTodo : todo;
339→        });
340→        if (todos.length > oldTodos.length) {
341→          mergedTodos.push(...todos.slice(oldTodos.length).filter(t => t.content));
342→        }
343→        syncMainTodoTree(source, mergedTodos);
344→        return { ...msg, timestamp, todos: mergedTodos };
345→      });
346→    } else {
347→      createTodoUpdateMessage(todos, event, sourceState, source, timestamp);
348→    }
349→  }
350→
351→  function finalizeTodo(todos: TodoItem[], event: ChatEvent, sourceState: SourceScopedState, source: StreamSource): void {
352→    const timestamp = resolveEventTimestamp(event);
353→    if (sourceState.todoMessageId) {
354→      if (todos.length > 0) {
355→        syncMainTodoTree(source, todos);
356→        updateById(sourceState.todoMessageId, msg => ({
357→          ...msg,
358→          timestamp,
359→          todos,
360→          ...getSubagentFields(source),
361→          source,
362→        }));
363→      }
364→      sourceState.todoBuffer = '';
365→    } else if (todos.length > 0) {
366→      createTodoUpdateMessage(todos, event, sourceState, source, timestamp);
367→    }
368→  }
369→
370→  function upsertToolDetailPreview(
371→    toolName: typeof TOOL_WRITE_FILE | typeof TOOL_EXECUTE,
372→    inputText: string,
373→    event: ChatEvent,
374→    sourceState: SourceScopedState,
375→    source: StreamSource,
376→  ): void {
377→    sourceState.currentAssistantId = undefined;
378→    sourceState.detailBuffers[toolName] = (sourceState.detailBuffers[toolName] || '') + (inputText || '');
379→    const parsed = parseStructuredInput(sourceState.detailBuffers[toolName] || '');
380→    if (!parsed) return;
381→
382→    const detail = buildToolDetailFromArgs(toolName, parsed, 'streaming');
383→    if (!detail) return;
384→
385→    const existingId = sourceState.detailMessageIds[toolName];
386→    const timestamp = resolveEventTimestamp(event);
387→    if (existingId) {
388→      updateById(existingId, msg => ({
389→        ...msg,
390→        event: EVENT_TOOL_INPUT,
391→        content: detail.summary,
392→        timestamp,
393→        toolName,
394→        node: event.node,
395→        toolDetail: detail,
396→        ...getSubagentFields(source),
397→        source,
398→      }));
399→      return;
400→    }
401→
402→    const messageId = generateId();
403→    sourceState.detailMessageIds[toolName] = messageId;
404→    push({
405→      id: messageId,
406→      role: 'assistant',
407→      content: detail.summary,
408→      timestamp,
409→      event: EVENT_TOOL_INPUT,
410→      toolName,
411→      node: event.node,
412→      toolDetail: detail,
413→      ...getSubagentFields(source),
414→      source,
415→    });
416→  }
417→
418→  function upsertToolDetailCall(
419→    toolName: typeof TOOL_WRITE_FILE | typeof TOOL_EXECUTE,
420→    data: Record<string, unknown>,
421→    event: ChatEvent,
422→    sourceState: SourceScopedState,
423→    source: StreamSource,
424→  ): void {
425→    const rawInput = typeof data.input === 'string' ? data.input : JSON.stringify(data.input ?? {});
426→    const parsed = parseStructuredInput(rawInput) || parseStructuredInput(sourceState.detailBuffers[toolName] || '');
427→    const previousDetail = getMessageById(sourceState.detailMessageIds[toolName])?.toolDetail;
428→    const detail = parsed
429→      ? buildToolDetailFromArgs(toolName, parsed, 'running')
430→      : previousDetail
431→        ? { ...previousDetail, status: 'running' as const, summary: previousDetail.summary }
432→        : undefined;
433→    if (!detail) return;
434→
435→    const timestamp = resolveEventTimestamp(event);
436→    const toolCallId = getToolCallId(data);
437→    const messageId = sourceState.detailMessageIds[toolName] || generateId();
438→    sourceState.detailMessageIds[toolName] = messageId;
439→    sourceState.detailBuffers[toolName] = '';
440→
441→    const nextDetail: ToolDetail = {
442→      ...detail,
443→      status: 'running',
444→      summary: detail.summary.replace(/ · .+$/, ' · 执行中'),
445→    };
446→
447→    if (getMessageById(messageId)) {
448→      updateById(messageId, msg => ({
449→        ...msg,
450→        event: EVENT_TOOL_CALL,
451→        content: nextDetail.summary,
452→        timestamp,
453→        toolName,
454→        toolCallId,
455→        node: event.node,
456→        toolDetail: nextDetail,
457→        ...getSubagentFields(source),
458→        source,
459→      }));
460→      return;
461→    }
462→
463→    push({
464→      id: messageId,
465→      role: 'assistant',
466→      content: nextDetail.summary,
467→      timestamp,
468→      event: EVENT_TOOL_CALL,
469→      toolName,
470→      toolCallId,
471→      node: event.node,
472→      toolDetail: nextDetail,
473→      ...getSubagentFields(source),
474→      source,
475→    });
476→  }
477→
478→  function finalizeToolDetailResult(
479→    toolName: typeof TOOL_WRITE_FILE | typeof TOOL_EXECUTE,
480→    data: Record<string, unknown>,
481→    event: ChatEvent,
482→    sourceState: SourceScopedState,
483→    source: StreamSource,
484→  ): void {
485→    const messageId = sourceState.detailMessageIds[toolName];
486→    if (!messageId) return;
487→    const existing = getMessageById(messageId);
488→    if (!existing?.toolDetail) return;
489→
490→    const isError = !!data.error;
491→    const output = toolName === TOOL_EXECUTE ? formatEventContent(event) : existing.toolDetail.output;
492→    const nextDetail: ToolDetail = {
493→      ...existing.toolDetail,
494→      status: isError ? 'error' : 'completed',
495→      output,
496→      summary: `${existing.toolDetail.title} · ${isError ? '失败' : '已完成'}`,
497→    };
498→
499→    updateById(messageId, msg => ({
500→      ...msg,
501→      event: EVENT_TOOL_CALL_RESULT,
502→      content: nextDetail.summary,
503→      timestamp: resolveEventTimestamp(event),
504→      toolName,
505→      toolCallId: getToolCallId(data) || msg.toolCallId,
506→      node: event.node,
507→      outputLength: typeof data.outputLength === 'number' ? data.outputLength as number : msg.outputLength,
508→      isError,
509→      toolDetail: nextDetail,
510→      ...getSubagentFields(source),
511→      source,
512→    }));
513→
514→    sourceState.detailMessageIds[toolName] = undefined;
515→    sourceState.detailBuffers[toolName] = '';
516→  }
517→
518→  function pushAssistantMessage(
519→    event: ChatEvent,
520→    source: StreamSource,
521→    content: string,
522→    overrides?: Partial<Message>,
523→  ): void {
524→    push({
525→      id: resolveEventId(event),
526→      role: 'assistant',
527→      content,
528→      timestamp: resolveEventTimestamp(event),
529→      node: event.node,
530→      ...overrides,
531→      ...getSubagentFields(source),
532→      source,
533→    });
534→  }
535→
536→  function handleUserEvent(event: ChatEvent): void {
537→    push({
538→      id: resolveEventId(event),
539→      role: 'user',
540→      content: getEventContent(event),
541→      timestamp: resolveEventTimestamp(event),
542→      event: EVENT_USER,
543→      node: event.node,
544→    });
545→  }
546→
547→  function handleTodoUpdateEvent(event: ChatEvent, sourceState: SourceScopedState, source: StreamSource): void {
548→    const todos = sanitizeTodoItems((event.data as Record<string, unknown>)?.todos);
549→    finalizeTodo(todos, event, sourceState, source);
550→  }
551→
552→  function handleGenerativeUIEvent(event: ChatEvent, sourceState: SourceScopedState, source: StreamSource): void {
553→    const payload = event.data as GenerativeUIPayload | undefined;
554→    if (payload?.spec) {
555→      finalizeGenerativeUI(payload, event, sourceState, source);
556→    }
557→  }
558→
559→  function handleSetGenerativeUIAnswer(event: ChatEvent): void {
560→    const data = event.data as Record<string, unknown> | undefined;
561→    const interruptId = typeof data?.interruptId === 'string' ? data.interruptId : undefined;
562→    const answer = data?.answer as string | Record<string, unknown> | undefined;
563→    if (!interruptId) return;
564→
565→    for (let i = state.messages.length - 1; i >= 0; i -= 1) {
566→      const msg = state.messages[i];
567→      if (msg.generativeUI?.interruptId === interruptId) {
568→        state.messages[i] = {
569→          ...msg,
570→          generativeUI: {
571→            ...msg.generativeUI,
572→            answer,
573→          } as GenerativeUIMessage,
574→        };
575→        break;
576→      }
577→    }
578→  }
579→
580→  function appendAssistantChunk(
581→    event: ChatEvent,
582→    sourceState: SourceScopedState,
583→    source: StreamSource,
584→    next: { content?: string; thinking?: string },
585→  ): void {
586→    const content = next.content || '';
587→    const thinking = next.thinking || '';
588→
589→    if (sourceState.currentAssistantId) {
590→      updateById(sourceState.currentAssistantId, msg => ({
591→        ...msg,
592→        content: msg.content + content,
593→        thinking: thinking ? (msg.thinking || '') + thinking : msg.thinking,
594→        ...getSubagentFields(source),
595→        source,
596→      }));
597→      return;
598→    }
599→
600→    if (!content && !thinking) {
601→      return;
602→    }
603→
604→    const id = resolveEventId(event);
605→    sourceState.currentAssistantId = id;
606→    push({
607→      id,
608→      role: 'assistant',
609→      content,
610→      thinking: thinking || undefined,
611→      timestamp: resolveEventTimestamp(event),
612→      event: EVENT_ASSISTANT,
613→      node: event.node,
614→      ...getSubagentFields(source),
615→      source,
616→    });
617→  }
618→
619→  function handleAssistantEvent(event: ChatEvent, sourceState: SourceScopedState, source: StreamSource): void {
620→    const content = getEventContent(event);
621→    const thinking = ((event.data as Record<string, unknown>)?.thinking as string) || '';
622→    appendAssistantChunk(event, sourceState, source, { content, thinking });
623→  }
624→
625→  function handleThinkingEvent(event: ChatEvent, sourceState: SourceScopedState, source: StreamSource): void {
626→    const data = event.data as Record<string, unknown>;
627→    const thinkingText = ((data?.thinking as string) || '') + ((data?.content as string) || '');
628→    appendAssistantChunk(event, sourceState, source, { thinking: thinkingText });
629→  }
630→
631→  function handleToolInputEvent(event: ChatEvent, sourceState: SourceScopedState, source: StreamSource): void {
632→    const { toolName, inputText } = getToolInputData(event);
633→
634→    if (toolName === TOOL_RENDER_UI) {
635→      sourceState.currentAssistantId = undefined;
636→      sourceState.generativeUIPreviewBuffer += inputText || '';
637→      const payload = parseGenerativeUIPreview(sourceState.generativeUIPreviewBuffer);
638→      if (payload) upsertGenerativeUIPreview(payload, event, sourceState, source);
639→      return;
640→    }
641→
642→    if (toolName === TOOL_WRITE_TODOS) {
643→      sourceState.todoBuffer += inputText || '';
644→      const todos = parseTodoItems(sourceState.todoBuffer);
645→      if (todos.length > 0) upsertTodo(todos, event, sourceState, source);
646→      return;
647→    }
648→
649→    if (isDetailToolName(toolName)) {
650→      upsertToolDetailPreview(toolName, inputText, event, sourceState, source);
651→      return;
652→    }
653→
654→    if (!inputText) {
655→      return;
656→    }
657→
658→    const last = state.messages[state.messages.length - 1];
659→    if (
660→      last?.event === EVENT_TOOL_INPUT &&
661→      last.toolName === toolName &&
662→      isSameSource(last.source, source)
663→    ) {
664→      updateById(last.id, msg => ({ ...msg, content: msg.content + inputText }));
665→      return;
666→    }
667→
668→    pushAssistantMessage(event, source, inputText, {
669→      event: EVENT_TOOL_INPUT,
670→      toolName,
671→    });
672→  }
673→
674→  function handleToolCallEvent(event: ChatEvent, sourceState: SourceScopedState, source: StreamSource): void {
675→    const data = event.data as Record<string, unknown>;
676→    const toolName = data?.name as string | undefined;
677→    const toolCallId = getToolCallId(data);
678→
679→    if (toolName === TOOL_WRITE_TODOS) {
680→      const input = typeof data?.input === 'string' ? data.input : JSON.stringify(data?.input ?? {});
681→      const todos = parseTodoItems(input);
682→      finalizeTodo(todos, event, sourceState, source);
683→      return;
684→    }
685→
686→    if (toolName && isDetailToolName(toolName)) {
687→      upsertToolDetailCall(toolName, data, event, sourceState, source);
688→      return;
689→    }
690→
691→    const content = formatEventContent(event);
692→    if (!content) {
693→      return;
694→    }
695→
696→    pushAssistantMessage(event, source, content, {
697→      event: EVENT_TOOL_CALL,
698→      toolName,
699→      toolCallId,
700→    });
701→  }
702→
703→  function handleToolCallResultEvent(event: ChatEvent, sourceState: SourceScopedState, source: StreamSource): void {
704→    const data = event.data as Record<string, unknown>;
705→    const toolName = data?.name as string | undefined;
706→    const toolCallId = getToolCallId(data);
707→    if (toolName === TOOL_WRITE_TODOS) return;
708→
709→    if (toolName && isDetailToolName(toolName)) {
710→      finalizeToolDetailResult(toolName, data, event, sourceState, source);
711→      return;
712→    }
713→
714→    const content = formatEventContent(event);
715→    const outputLength = typeof data?.outputLength === 'number' ? data.outputLength as number : undefined;
716→    const isError = !!data?.error;
717→    if (!content) {
718→      return;
719→    }
720→
721→    pushAssistantMessage(event, source, content, {
722→      event: EVENT_TOOL_CALL_RESULT,
723→      toolName,
724→      toolCallId,
725→      outputLength,
726→      isError,
727→    });
728→  }
729→
730→  function handleDeliverEvent(event: ChatEvent, source: StreamSource): void {
731→    const content = formatEventContent(event);
732→    if (!content) {
733→      return;
734→    }
735→
736→    pushAssistantMessage(event, source, content, {
737→      event: EVENT_DELIVER,
738→    });
739→  }
740→
741→  function handleSimpleAssistantEvent(event: ChatEvent, source: StreamSource): void {
742→    const content = formatEventContent(event);
743→    const data = event.data as Record<string, unknown> | undefined;
744→    const toolName =
745→      event.event === EVENT_ERROR
746→        ? ((data?.toolName as string) || (data?.name as string) || undefined)
747→        : ((data?.name as string) || (data?.agentName as string) || event.node);
748→
749→    pushAssistantMessage(event, source, content, {
750→      event: event.event,
751→      toolName,
752→      isError: event.event === EVENT_ERROR ? true : undefined,
753→    });
754→  }
755→
756→  function applyEvent(event: ChatEvent): void {
757→    const { event: type } = event;
758→    const source = resolveEventSource(event);
759→    const sourceState = getSourceState(source);
760→
761→    // subagent 的 agent-end / assistant-end 推空消息用于 UI 标记结束边界；
762→    // main source 的同类事件在下方的 FILTERED_MESSAGE_EVENT_SET 中被过滤掉。
763→    if ((type === EVENT_AGENT_END || type === EVENT_ASSISTANT_END) && source.kind === 'subagent') {
764→      sourceState.currentAssistantId = undefined;
765→      const usage = type === EVENT_ASSISTANT_END ? parseTokenUsageFromAssistantEndData(event.data) : undefined;
766→      pushAssistantMessage(event, source, '', {
767→        event: type,
768→        ...(usage ? { tokenUsage: { inputTokens: usage.inputTokens, outputTokens: usage.outputTokens, totalTokens: usage.totalTokens } } : {}),
769→      });
770→      return;
771→    }
772→
773→    // 生命周期/控制事件由前端显式过滤，不产出消息（仅对 main source 生效）。
774→    if (FILTERED_MESSAGE_EVENT_SET.has(type)) {
775→      sourceState.currentAssistantId = undefined;
776→      return;
777→    }
778→
779→    // ── 用户消息 ─────────────────────────────────────────────────────────────────
780→    if (type === EVENT_USER) {
781→      sourceState.currentAssistantId = undefined;
782→      handleUserEvent(event);
783→      return;
784→    }
785→
786→    // ── todo-update 自定义事件（on_tool_start 触发，携带完整 todos 数组）────────────
787→    if (type === EVENT_TODO_UPDATE) {
788→      sourceState.currentAssistantId = undefined;
789→      handleTodoUpdateEvent(event, sourceState, source);
790→      return;
791→    }
792→
793→    // ── generative-ui 事件（render-ui 工具产出）─────────────────────────────────────
794→    if (type === EVENT_GENERATIVE_UI) {
795→      sourceState.currentAssistantId = undefined;
796→      handleGenerativeUIEvent(event, sourceState, source);
797→      return;
798→    }
799→
800→    // ── set-generative-ui-answer（resume 时回写用户选择）─────────────────────────────
801→    if (type === EVENT_SET_GENERATIVE_UI_ANSWER) {
802→      handleSetGenerativeUIAnswer(event);
803→      return;
804→    }
805→
806→    // ── assistant / thinking ──────────────────────────────────────────────────────
807→    if (type === EVENT_ASSISTANT) {
808→      handleAssistantEvent(event, sourceState, source);
809→      return;
810→    }
811→
812→    if (type === EVENT_THINKING) {
813→      handleThinkingEvent(event, sourceState, source);
814→      return;
815→    }
816→
817→    // 非 assistant 事件重置当前 assistant 追踪
818→    sourceState.currentAssistantId = undefined;
819→
820→    // ── context-summarized ───────────────────────────────────────────────────────
821→    if (type === EVENT_CONTEXT_SUMMARIZED) {
822→      const data = event.data as Record<string, unknown> | undefined;
823→      const message = (data?.message as string) || 'Context 已压缩';
824→      pushAssistantMessage(event, source, message, {
825→        event: EVENT_CONTEXT_SUMMARIZED,
826→      });
827→      return;
828→    }
829→
830→    // ── tool-input ────────────────────────────────────────────────────────────────
831→    if (type === EVENT_TOOL_INPUT) {
832→      handleToolInputEvent(event, sourceState, source);
833→      return;
834→    }
835→
836→    // ── tool-call ─────────────────────────────────────────────────────────────────
837→    if (type === EVENT_TOOL_CALL) {
838→      handleToolCallEvent(event, sourceState, source);
839→      return;
840→    }
841→
842→    // ── tool-call-result ──────────────────────────────────────────────────────────
843→    if (type === EVENT_TOOL_CALL_RESULT) {
844→      handleToolCallResultEvent(event, sourceState, source);
845→      return;
846→    }
847→
848→    // ── deliver ───────────────────────────────────────────────────────────────────
849→    if (type === EVENT_DELIVER) {
850→      handleDeliverEvent(event, source);
851→      return;
852→    }
853→
854→    // ── error / tool-output ───────────────────────────────────────────────────────
855→    if (type === EVENT_ERROR || type === EVENT_TOOL_OUTPUT) {
856→      handleSimpleAssistantEvent(event, source);
857→    }
858→  }
859→
860→  return {
861→    applyEvent,
862→    /** 返回当前消息列表的浅拷贝（供 setMessages 使用） */
863→    getMessages: (): Message[] => [...state.messages],
864→    getTodoTree: (): TodoTreeItem[] => [...state.todoTree],
865→  };
866→}
