 70→const parseStreamChunk = (buffer: string, onChunk: (event: ChatEvent) => void) => {
 71→  const lines = buffer.split('\n');
 72→  let remaining = lines.pop() || '';
 73→  
 74→  for (const line of lines) {
 75→      const trimmed = line.trim();
 76→      if (trimmed) {
 77→          try {
 78→              const rawEvent = JSON.parse(trimmed) as Partial<ChatEvent> & Record<string, unknown>;
 79→              const event: ChatEvent = {
 80→                  event: (rawEvent.event as ChatEvent['event']) || EVENT_ERROR,
 81→                  data: rawEvent.data,
 82→                  node: typeof rawEvent.node === 'string' ? rawEvent.node : undefined,
 83→                  timestamp: typeof rawEvent.timestamp === 'number' ? rawEvent.timestamp : undefined,
 84→                  subagentType: typeof rawEvent.subagent_type === 'string' ? rawEvent.subagent_type : undefined,
 85→                  subagentNamespace: typeof rawEvent.subagent_namespace === 'string' ? rawEvent.subagent_namespace : undefined,
 86→                  source:
 87→                    rawEvent.source && typeof rawEvent.source === 'object'
 88→                      ? rawEvent.source as ChatEvent['source']
 89→                      : undefined,
 90→              };
