import { BadRequestException, Inject, Injectable, Logger, Scope } from '@nestjs/common';
import { Request, Response } from 'express';
import { PassThrough } from 'stream';
import { randomUUID } from 'crypto';
import { InjectModel } from '@nestjs/mongoose';
import { Model } from 'mongoose';
import { Command } from '@langchain/langgraph';
import { Conversation } from '../conversation/conversation.entity';
import { ConversationService } from '../conversation/conversation.service';
import { EventsService, ILinkedEvent } from '../events/events.service';
import { formatError, getErrorCauseChain, retry } from '../../common/utils';
import { AgentsService, IGraphEvent } from '../../agents/agents.service';
import { TalkableAgents } from '../../common/constant';
import { ChatDto } from './chat.dto';
import { normalizeResumePayload, normalizeSlashSkillMentions } from './chat.payload';
import { ConversationSandboxManager } from '../../agents/sandbox/conversation-sandbox.manager';
import { ConversationTokenUsage } from '../conversation/conversation.entity';
import { normalizeSessionFileContent } from './session-file-content';
import { listLocalSkillNames } from '../../agents/sandbox/providers/initial-files.provider';
import { filterSessionFilesForResponse } from './session-files';

@Injectable({ scope: Scope.DEFAULT })
export class ChatService {
  @Inject()
  private graph!: AgentsService;

  @Inject()
  private conversation!: ConversationService;

  @Inject()
  private events!: EventsService;

  @Inject()
  private sandboxManager!: ConversationSandboxManager;

  @InjectModel(Conversation.name)
  private conversationModel!: Model<Conversation>;

  private readonly logger = new Logger(ChatService.name);

  private toClientEvent<T extends Record<string, unknown>>(chunk: T) {
    const { id, timestamp, ...rest } = chunk;
    return rest;
  }

  private extractTokenUsageFromAssistantEnd(chunk: ILinkedEvent): ConversationTokenUsage | undefined {
    if (chunk.event !== 'assistant-end') {
      return undefined;
    }
    const data = chunk.data as Record<string, unknown> | undefined;
    if (!data || typeof data !== 'object') {
      return undefined;
    }
    const usage = data.usage as Record<string, unknown> | undefined;
    if (!usage || typeof usage !== 'object') {
      return undefined;
    }

    const inputTokens = typeof usage.inputTokens === 'number' ? usage.inputTokens : undefined;
    const outputTokens = typeof usage.outputTokens === 'number' ? usage.outputTokens : undefined;
    const totalTokens = typeof usage.totalTokens === 'number' ? usage.totalTokens : undefined;
    if (
      typeof inputTokens !== 'number' ||
      typeof outputTokens !== 'number' ||
      typeof totalTokens !== 'number'
    ) {
      return undefined;
    }

    const promptTokens = typeof usage.promptTokens === 'number' ? usage.promptTokens : undefined;
    const completionTokens = typeof usage.completionTokens === 'number' ? usage.completionTokens : undefined;
    const cachedInputTokens = typeof usage.cachedInputTokens === 'number' ? usage.cachedInputTokens : undefined;
    const reasoningOutputTokens = typeof usage.reasoningOutputTokens === 'number' ? usage.reasoningOutputTokens : undefined;

    return {
      inputTokens,
      outputTokens,
      totalTokens,
      ...(typeof promptTokens === 'number' ? { promptTokens } : {}),
      ...(typeof completionTokens === 'number' ? { completionTokens } : {}),

