// 常量定义文件
// 所有硬编码字符串常量应集中在此文件中

// API 配置
export const API_BASE_URL = 'http://localhost:8085/api';

// 模型配置
export type ModelId = string;

export const DEFAULT_MODEL: ModelId = 'moonshotai/kimi-k2.5';

// ChatEvent 事件类型
export const EVENT_USER = 'user';
export const EVENT_ASSISTANT = 'assistant';
export const EVENT_ERROR = 'error';
export const EVENT_END = 'end';
export const EVENT_TOOL_INPUT = 'tool-input';
export const EVENT_TOOL_OUTPUT = 'tool-output';
export const EVENT_TOOL_CALL = 'tool-call';
export const EVENT_TOOL_CALL_RESULT = 'tool-call-result';
export const EVENT_CONVERSATION_CREATE = 'conversation-create';
export const EVENT_DELIVER = 'deliver';
export const EVENT_AGENT_START = 'agent-start';
export const EVENT_AGENT_END = 'agent-end';
export const EVENT_ASSISTANT_START = 'assistant-start';
export const EVENT_ASSISTANT_END = 'assistant-end';
export const EVENT_THINKING = 'thinking';
export const EVENT_GENERATIVE_UI = 'generative-ui';
export const EVENT_SET_GENERATIVE_UI_ANSWER = 'set-generative-ui-answer';
export const EVENT_CONTEXT_SUMMARIZED = 'context-summarized';
export const EVENT_TODO_UPDATE = 'todo-update';

// 这些事件属于流控制/生命周期信号，不会被渲染为消息。
export const FILTERED_MESSAGE_EVENTS = [
  EVENT_CONVERSATION_CREATE,
  EVENT_AGENT_START,
  EVENT_AGENT_END,
  EVENT_ASSISTANT_START,
  EVENT_ASSISTANT_END,
  EVENT_END,
] as const;

// 工具名称
export const TOOL_RENDER_UI = 'render-ui';
export const TOOL_WRITE_TODOS = 'write_todos';
export const TOOL_WRITE_FILE = 'write_file';
export const TOOL_EXECUTE = 'execute';

// 事件标签映射
export const EVENT_LABELS: Record<string, string | null> = {
  [EVENT_TOOL_INPUT]: 'Tool Input',
  [EVENT_TOOL_CALL]: 'Tool Call',
  [EVENT_TOOL_CALL_RESULT]: 'Tool Result',
  [EVENT_TOOL_OUTPUT]: 'Tool Output',
  [EVENT_DELIVER]: 'Deliver',
  [EVENT_ERROR]: 'Error',
  [EVENT_CONTEXT_SUMMARIZED]: 'Context',
};

// 工具调用相关的事件类型列表
export const TOOL_CALL_EVENTS = [
  EVENT_TOOL_INPUT,
  EVENT_TOOL_CALL,
  EVENT_TOOL_CALL_RESULT,
  EVENT_TOOL_OUTPUT,
];

export const SearchResultMaxLength = 256;

export const SearchErrorMessage = '未查询到相关信息';


export enum ENodeName {
  Coordinator = 'coordinator',
  Planner = 'planner',
  Researcher = 'researcher',
  Writer = 'writer',
}

export const TalkableAgents: ENodeName[] = [
  ENodeName.Coordinator,
  ENodeName.Planner,
  ENodeName.Researcher,
  ENodeName.Writer,
];

export enum EToolName {
  RenderUI = 'render-ui',
  Dispatch = 'dispatch',
  TextToImage = 'text-to-image',
  Execute = 'execute',
  Planning = 'planning',
  Next = 'next',
  Deliver = 'deliver',
  GetGeolocation = 'get-geolocation',
  GetWeather = 'get-weather',
  GetTrainRoute = 'get-train-route',
  SearchPoiByType = 'search-poi-by-type',
  SearchPoiByName = 'search-poi-by-name',
  SearchPoiByLocation = 'search-poi-by-location',
  FileReader = 'file-reader',
  VideoReader = 'video-reader',
  ImageReader = 'image-reader',
  GetCurrentTime = 'get-current-time',
  WriteTodos = 'write_todos',
  WriteFile = 'write_file',
}

// 这些工具都需要在模型流式生成参数时提前透出 tool-input，
// 让前端能在工具真正执行前展示表单或 TODO 预览。
// write_file 会携带大段正文，继续透传会放大 SSE / history / 前端聚合成本，因此移除。
export const ALLOW_TOOL_INPUT: string[] = [
  EToolName.RenderUI,
  EToolName.WriteTodos,
  EToolName.Execute,
  'task',
];

// 这些工具的结果可能包含大段文件正文，只向前端透出首尾摘要，避免消息和历史回放卡顿。
export const SUMMARIZED_TOOL_CALL_RESULT_NAMES: string[] = [
  EToolName.WriteFile,
  EToolName.FileReader,
  'query_prometheus',
  'get_dashboard_panel_queries',
];

export const ReusableTools: string[] = [
  EToolName.GetGeolocation,
  EToolName.GetWeather,
  EToolName.GetTrainRoute,
  EToolName.SearchPoiByLocation,
  EToolName.SearchPoiByName,
  EToolName.SearchPoiByType,
  EToolName.VideoReader,
  EToolName.ImageReader,
  EToolName.TextToImage,
];

export const InternalTools: string[] = [EToolName.Planning, EToolName.Next, EToolName.Deliver];

export enum ETaskStatus {
  Successful = 'successful',
  InformationRequired = 'information-required',
  Failed = 'failed',
}

export const TaskStatusText = {
  [ETaskStatus.Successful]: '成功',
  [ETaskStatus.InformationRequired]: '需要补充信息',
  [ETaskStatus.Failed]: '失败',
};

