function toSpec(raw: Record<string, unknown>): Spec {
  return {
    root: (raw.root as string) ?? 'main',
    elements: (raw.elements as Record<string, unknown>) ?? {},
    state: (raw.state as Record<string, unknown>) ?? {},
    ...raw,
  } as unknown as Spec;
}

/**
 * Minimal spec renderer following the official @json-render/react pattern:
 * StateProvider → VisibilityProvider → ActionProvider → ValidationProvider → Renderer
 */
function SpecRenderer({
  spec: rawSpec,
  interactive,
  loading,
  onSubmit,
}: {
  spec: Record<string, unknown>;
  interactive: boolean;
  loading: boolean;
  onSubmit: (data: Record<string, unknown> | null) => void;
}) {
  const spec = toSpec(rawSpec);
  const store = createStateStore((spec.state as Record<string, unknown>) ?? {});

  const handlers = interactive
    ? {
        submit: () => { onSubmit(store.getSnapshot() as Record<string, unknown>); },
        cancel: () => { onSubmit(null); },
      }
    : {};

  return (
    <div className="rounded border p-4">
      <StateProvider store={store}>
        <VisibilityProvider>
          <ActionProvider handlers={handlers}>
            <ValidationProvider>
              <Renderer spec={spec} registry={registry} loading={loading} />
