import { useState, useRef, useCallback } from 'react';
import { parse as parsePartialJson } from 'partial-json';
import {
  Renderer,
  StateProvider,
  ActionProvider,
  VisibilityProvider,
  ValidationProvider,
  createStateStore,
} from '@json-render/react';
import type { Spec } from '@json-render/core';
import { registry } from '@/lib/generative-ui/registry';
import { API_BASE_URL } from '@/lib/const';
import axios from 'axios';

/**
 * Filter the streamed spec to only include elements with valid type/props,
 * enabling progressive rendering as the AI response builds up.
 * Returns null if the spec is not yet renderable.
 */
function buildSafeSpec(rawSpec: Record<string, unknown>): Spec | null {
  if (!rawSpec?.root || !rawSpec?.elements) return null;
  const elements = rawSpec.elements as Record<string, Record<string, unknown>>;
  const rootEl = elements[rawSpec.root as string];
  if (!rootEl?.type || rootEl?.props == null) return null;

  const safeElements: Record<string, unknown> = {};
  for (const [key, el] of Object.entries(elements)) {
    if (el?.type && el?.props != null) {
      safeElements[key] = el;
    }
  }
  return {
    root: rawSpec.root,
    elements: safeElements,
    ...(rawSpec.state ? { state: rawSpec.state } : {}),
  } as unknown as Spec;
}

/**
 * Minimal spec renderer following the official @json-render/react pattern:
 * StateProvider → VisibilityProvider → ActionProvider → ValidationProvider → Renderer
 */
function SpecRenderer({
  spec: rawSpec,
  interactive,
  loading,
  onSubmit,
}: {
  spec: Record<string, unknown>;
  interactive: boolean;
  loading: boolean;
  onSubmit: (data: Record<string, unknown> | null) => void;
}) {
  const spec = buildSafeSpec(rawSpec);
  const initState = (rawSpec.state as Record<string, unknown>) ?? {};
  const store = createStateStore(initState);

  const handlers: Record<string, () => void> = {};
  if (interactive) {
    handlers.submit = () => { onSubmit(store.getSnapshot() as Record<string, unknown>); };
    handlers.cancel = () => { onSubmit(null); };
  }

  return (
    <div className="rounded border p-4">
      <StateProvider store={store}>
        <VisibilityProvider>
          <ActionProvider handlers={handlers}>
            <ValidationProvider>
              <Renderer spec={spec} registry={registry} loading={loading} />
            </ValidationProvider>
          </ActionProvider>
        </VisibilityProvider>
      </StateProvider>
    </div>
  );
}

