function parseGenerativeUIPreview(accumulated: string): GenerativeUIMessage | undefined {
  try {
    const parsed = parsePartialJson(accumulated);
    if (!parsed || typeof parsed !== 'object') return undefined;

    const data = parsed as Record<string, unknown>;
    const title = asString(data.title) || '';
    const spec = data.spec as Record<string, unknown> | undefined;
    if (!title && !spec) return undefined;

    return {
      title: title || 'UI',
      spec: spec ?? {},
      interactive: data.interactive === true,
      isPreview: true,
    };
  } catch {
    return undefined;
  }
}

