function parseGenerativeUIPreview(accumulated: string): GenerativeUIMessage | undefined {
  try {
    const parsed = parsePartialJson(accumulated);
    if (!parsed || typeof parsed !== 'object') return undefined;

    const data = parsed as Record<string, unknown>;
    const title = asString(data.title) || '';
    const rawSpec = data.spec as Record<string, unknown> | undefined;
    if (!title && !rawSpec) return undefined;

    // Filter to only include elements with valid type/props for progressive rendering
    const spec = rawSpec ? buildSafeSpecRaw(rawSpec) : {};

    return {
      title: title || 'UI',
      spec,
      interactive: data.interactive === true,
      isPreview: true,
    };
  } catch {
    return undefined;
  }
}

/**
 * Inline safe-spec filter for messageProcessor (avoids importing from @json-render/core).
 * Only keeps elements with valid type + props so partial streaming doesn't break the renderer.
 */
function buildSafeSpecRaw(rawSpec: Record<string, unknown>): Record<string, unknown> {
  if (!rawSpec?.root || !rawSpec?.elements) return rawSpec;
  const elements = rawSpec.elements as Record<string, Record<string, unknown>>;
  const rootEl = elements[rawSpec.root as string];
  if (!rootEl?.type || rootEl?.props == null) return rawSpec;

  const safeElements: Record<string, unknown> = {};
  for (const [key, el] of Object.entries(elements)) {
    if (el?.type && el?.props != null) {
      safeElements[key] = el;
    }
  }
  return {
    root: rawSpec.root,
    elements: safeElements,
    ...(rawSpec.state ? { state: rawSpec.state } : {}),
  };
}

