        }
        await this.conversationModel.updateOne({ id }, partial);
        buffer = chunk;
      }
    } else if (chunk) {
      buffer = chunk;
      // 仅在对话没有 head 时才记录（避免因 Redis 丢失 tail 数据时覆盖已有的历史链）
      if (!conversation?.head) {
        await this.conversationModel.updateOne({ id }, { head: chunk.id });
      }
    }
  };
}

