private async pipe(
  id: string,
  generator: AsyncGenerator<IGraphEvent>,
  response: PassThrough,
  ac: AbortController,
  save: (chunk?: ILinkedEvent) => Promise<void>,
) {
  const aggregate = this.createChunkAggregator();

  /**
   * 立即写入 response 流，DB 持久化异步进行不阻塞响应。
   * 之前是 await save() → response.write()，串行的 DB 操作（Redis + MongoDB）
   * 会导致快速到来的 chunk 排队，前端一次性收到一批事件而非逐条流式。
   */
  const emit = (chunk: ILinkedEvent) => {
    if (!response.destroyed) {
      const payload = this.toClientEvent(chunk as unknown as Record<string, unknown>);
      response.write(`${JSON.stringify(payload)}\n`);
    }
  };

  const persist = async (chunk: ILinkedEvent) => {
    const tokenUsage = this.extractTokenUsageFromAssistantEnd(chunk);
    if (tokenUsage) {
      await this.conversationModel.updateOne({ id }, { tokenUsage });
    }
    await save(aggregate(chunk as IGraphEvent));
  };

  const writeKeepAlive = () => {
    if (!response.destroyed) {
      response.write('\n');
    }
  };

  // 收集后台持久化 promise，在流结束后等待全部完成
  const pendingPersists: Promise<void>[] = [];

  try {
    await this.conversation.start(id);

    const keepAliveInterval = setInterval(writeKeepAlive, 15_000);
    try {
      for await (const chunk of generator) {
        await this.checkAborted(id, ac);
        // 先写 response（同步），再异步持久化
        emit(chunk);
        pendingPersists.push(
          persist(chunk).catch(err =>
            this.logger.error({ conversationId: id, error: err }, 'Failed to persist chunk'),
          ),
        );
      }
    } finally {
      clearInterval(keepAliveInterval);
    }

    const endChunk: ILinkedEvent = { id: randomUUID(), event: 'end', timestamp: Date.now() };
    emit(endChunk);
    pendingPersists.push(
      persist(endChunk).catch(err =>
        this.logger.error({ conversationId: id, error: err }, 'Failed to persist end chunk'),
      ),
    );
  } catch (error) {
    const message = formatError(error);
    const causeChain = getErrorCauseChain(error);
    this.logger.error({
      conversationId: id,
      message,
      causeChain,
      rootCause: causeChain[causeChain.length - 1],
      aborted: ac.signal.aborted,
    }, 'Chat stream failed');

    const errorChunk: ILinkedEvent = { id: randomUUID(), event: 'error', data: message, timestamp: Date.now() };
    emit(errorChunk);
    pendingPersists.push(
      persist(errorChunk).catch(err =>
        this.logger.error({ conversationId: id, error: err }, 'Failed to persist error chunk'),
      ),
    );
  } finally {
    // 等待所有持久化完成后再关闭流和保存最终状态
    await Promise.allSettled(pendingPersists);
    save();
    response.end();
    await this.conversation.stop(id);
  }
}

